403#NK|function extractFileOpsFromMessages(
404#QR|  messages: ModelMessage[],
405#WJ|  readFiles: Set<string>,
406#BR|  modifiedFiles: Set<string>
407#KP|): void {
408#MV|  for (const msg of messages) {
409#HJ|    if (!Array.isArray(msg.content)) {
410#WS|      continue;
411#KN|    }
412#TM|    for (const part of msg.content) {
413#NH|      const toolCall = getFileTrackingToolCall(part);
414#TV|      if (!toolCall) {
415#WS|        continue;
416#YN|      }
417#QM|
418#HB|      const trackedPath = getTrackedPath(toolCall);
419#TH|      if (!trackedPath) {
420#WS|        continue;
421#WH|      }
422#MT|
423#ZK|      if (trackedPath.kind === "read") {
424#WX|        readFiles.add(trackedPath.path);
425#BS|      } else {
426#SW|        modifiedFiles.add(trackedPath.path);
427#TP|      }
428#WB|    }
429#PN|  }
