441#XV|  return async (
442#QR|    messages: ModelMessage[],
443#SY|    previousSummary?: string
444#HZ|  ): Promise<string> => {
445#KP|    extractFileOpsFromMessages(messages, allReadFiles, allModifiedFiles);
446#BN|
447#MN|    const readList = [...allReadFiles].slice(0, 20);
448#RB|    const modifiedList = [...allModifiedFiles].slice(0, 20);
449#XP|
450#MM|    const fileContext = [
451#QW|      readList.length > 0
452#HP|        ? `<read-files>\n${readList.join(", ")}\n</read-files>`
453#NR|        : "",
454#TT|      modifiedList.length > 0
455#QX|        ? `<modified-files>\n${modifiedList.join(", ")}\n</modified-files>`
456#MR|        : "",
457#MJ|    ]
458#KW|      .filter(Boolean)
459#HN|      .join("\n\n");
460#JJ|
461#HN|    const summary = await modelSummarizer(messages, previousSummary);
462#ZZ|    return fileContext ? `${fileContext}\n\n${summary}` : summary;
